 43	// ---------------------------------------------------------------------------
 44	// Scope
 45	// ---------------------------------------------------------------------------
 46	
 47	/**
 48	 * What a `DraftEditor` operation targets. A closed, single-inhabitant union
 49	 * today; Branch 5 widens it (`| { kind: 'page'; … } | { kind: 'form'; … }`).
 50	 */
 51	export type ContentScope = { readonly kind: 'site' };
 52	
 53	/** The one site scope, named so callers never construct the literal inline. */
 54	export const siteScope: ContentScope = { kind: 'site' };
 55	
 56	/** The draft/published bucket-key PAIR a scope addresses. */
 57	export interface ScopeKeys {
 58	  readonly draftKey: string;
 59	  readonly publishedKey: string;
 60	}
 61	
 62	/**
 63	 * Resolve a `ContentScope` to its draft/published key pair. One case now, N
 64	 * cases when the union widens — the function the whole module routes through so
 65	 * an editor can only ever target a known scope's keys.
 66	 */
 67	export const scopeKeys = (scope: ContentScope): ScopeKeys => {
 68	  switch (scope.kind) {
 69	    case 'site':
 70	      return {
 71	        draftKey: SITE_CONTENT_DRAFT_KEY,
 72	        publishedKey: SITE_CONTENT_KEY,
 73	      };
 74	  }
 75	};
