 77	// ---------------------------------------------------------------------------
 78	// Codecs (the document's on-bucket JSON ↔ decoded value)
 79	// ---------------------------------------------------------------------------
 80	
 81	const decodeDocumentJson = Schema.decodeUnknownEffect(
 82	  Schema.fromJsonString(SiteContent),
 83	);
