 85	// ---------------------------------------------------------------------------
 86	// Service
 87	// ---------------------------------------------------------------------------
 88	
 89	export class Service extends Context.Service<
 90	  Service,
 91	  {
 92	    /**
 93	     * Load the document the `/admin` editor edits for `scope`: the unpublished
 94	     * draft when it is strictly newer than the published document, else the
 95	     * published document, else the bundled defaults. The reconciliation is by
 96	     * bucket `lastModified`, not by mere draft *presence*, so a stale or
 97	     * failed-delete draft can never reopen as the edit source. Never fails (a
 98	     * bad draft is logged and ignored), so the editor always opens.
 99	     */
100	    readonly load: (scope: ContentScope) => Effect.Effect<AdminContent>;
101	  }
102	>()('gycc/lib/content/draft-editor.server/Service') {}
103	
104	export const layer = Layer.effect(
105	  Service,
106	  Effect.gen(function* () {
107	    const storage = yield* Storage.Service;
108	
109	    /**
110	     * Read + decode the document at `key`, or `Option.none()` when it is absent
111	     * / unreadable / malformed (logged, never thrown — a bad draft must not
112	     * break the editor open).
113	     */
114	    const readDocument = Effect.fnUntraced(
115	      function* (key: string) {
116	        const object = yield* storage.get(key);
117	        const json = yield* Effect.promise(() =>
118	          new Response(object.stream).text(),
119	        );
120	        return Option.some(yield* decodeDocumentJson(json));
121	      },
122	      (effect, key) =>
123	        effect.pipe(
124	          Effect.catchCause((cause) =>
125	            Effect.logWarning(
126	              `DraftEditor: could not read ${key}`,
127	              cause,
128	            ).pipe(Effect.as(Option.none<SiteContentType>())),
129	          ),
130	        ),
131	    );
132	
133	    const load = Effect.fn('DraftEditor.load')(function* (
134	      scope: ContentScope,
135	    ) {
136	      const { draftKey, publishedKey } = scopeKeys(scope);
137	      const draft = yield* readDocument(draftKey);
138	      const published = yield* readDocument(publishedKey);
139	
140	      if (Option.isSome(draft)) {
141	        if (Option.isNone(published)) {
142	          return { content: draft.value, source: 'draft' as const };
143	        }
144	        const draftHead = yield* storage
145	          .head(draftKey)
146	          .pipe(Effect.orElseSucceed(() => Option.none<ObjectHead>()));
147	        const publishedHead = yield* storage
148	          .head(publishedKey)
149	          .pipe(Effect.orElseSucceed(() => Option.none<ObjectHead>()));
150	        const draftIsNewer =
151	          Option.isSome(draftHead) &&
152	          Option.isSome(publishedHead) &&
153	          draftHead.value.lastModified.getTime() >
154	            publishedHead.value.lastModified.getTime();
155	        if (draftIsNewer) {
156	          return { content: draft.value, source: 'draft' as const };
157	        }
158	        return { content: published.value, source: 'published' as const };
159	      }
160	
161	      if (Option.isSome(published)) {
162	        return { content: published.value, source: 'published' as const };
163	      }
164	      return { content: defaultContent, source: 'defaults' as const };
165	    });
166	
167	    return Service.of({ load });
168	  }),
169	);
