299	/** Where the editor's content originated, for the admin banner. */
300	export type AdminContentSource = 'draft' | 'published' | 'defaults';
301	
302	export interface AdminContent {
303	  readonly content: SiteContentType;
304	  readonly source: AdminContentSource;
