307	/**
308	 * Cache TTL. Short by design (D3 — runtime read with cache, no redeploy): a
309	 * publish becomes visible on the next read after the TTL elapses (or the
310	 * editor's explicit `bust`). 30s keeps the bucket-read rate negligible while
311	 * making edits feel near-instant.
312	 */
313	const CACHE_TTL_MS = 30_000;
314	
315	const decodeDocument = Schema.decodeUnknownEffect(Schema.fromJsonString(SiteContent));
316	
317	export class Service extends Context.Service<
318	  Service,
319	  {
