364	  Service,
365	  Effect.gen(function* () {
366	    const storage = yield* Storage.Service;
367	
368	    /**
369	     * Read + decode the `SiteContent` document at `key`, or `Option.none()`
370	     * when it is absent / unreadable / malformed. Shared by the public read
371	     * path (which maps `none` to the bundled defaults) and the admin read
372	     * path (which tries the draft, then the published key, then defaults).
373	     */
374	    const readDocument = Effect.fnUntraced(
375	      function* (key: string) {
376	        const object = yield* storage.get(key);
377	        const json = yield* Effect.promise(() =>
378	          new Response(object.stream).text(),
379	        );
380	        return Option.some(yield* decodeDocument(json));
381	      },
382	      (effect, key) =>
383	        effect.pipe(
384	          Effect.catchCause((cause) =>
385	            Effect.logWarning(`Content: could not read ${key}`, cause).pipe(
386	              Effect.as(Option.none<SiteContentType>()),
387	            ),
388	          ),
389	        ),
390	    );
391	
392	    /**
393	     * Read + decode the document from the bucket, falling back to the bundled
394	     * defaults on every failure mode (`boundary-discipline`, D3):
395	     *   - no bucket configured → `Storage.layerOptional` yields a disabled
396	     *     storage whose `get` reports `NotFound`;
397	     *   - object absent / empty → `NotFound`;
398	     *   - bucket unreachable or document malformed → any other failure /
399	     *     decode error / unexpected defect.
