495	            .pipe(Effect.orElseSucceed(() => Option.none<ObjectHead>()));
496	          const publishedHead = yield* storage
497	            .head(SITE_CONTENT_KEY)
498	            .pipe(Effect.orElseSucceed(() => Option.none<ObjectHead>()));
